parameters.jsCode:
const topics = [
  { theme: 'personajes', prompt: 'Escribe un artículo detallado sobre los protagonistas confirmados de GTA 6: Jason y Lucia. Explica lo que sabemos sobre su historia, su relación como pareja criminal inspirada en Bonnie y Clyde, y las teorías de los fans sobre su arco narrativo. Incluye referencias a los trailers oficiales.' },
  { theme: 'mapa', prompt: 'Escribe un artículo sobre el mapa de GTA 6 ambientado en Leonida (inspirado en Florida/Miami). Analiza las localizaciones vistas en los trailers: Vice City, los Everglades, las playas, los centros comerciales. Compara con Vice City de GTA Vice City y explica qué mejoras se esperan.' },
  { theme: 'gameplay', prompt: 'Escribe un artículo sobre las mecánicas de juego confirmadas y rumoreadas de GTA 6. Incluye el sistema de protagonistas duales, la evolución del combate, la conducción, las actividades secundarias y las mejoras en la inteligencia artificial de los NPCs.' },
  { theme: 'online', prompt: 'Escribe un artículo sobre lo que podemos esperar de GTA Online 2. Analiza cómo GTA Online evolucionó con GTA V, los ingresos que generó para Rockstar, y las teorías sobre las nuevas funcionalidades multijugador de GTA 6.' },
  { theme: 'comparativa', prompt: 'Escribe un artículo comparativo entre GTA V y GTA 6. Compara gráficos, mundo abierto, inteligencia artificial, físicas, detalle del entorno, y la evolución técnica basándote en lo visto en los trailers de GTA VI.' },
  { theme: 'historia', prompt: 'Escribe un artículo sobre la posible historia de GTA 6. Basándote en los trailers, analiza la ambientación en la era moderna, la cultura latina de Vice City/Miami, las redes sociales dentro del juego, y las teorías sobre la trama principal.' },
  { theme: 'rockstar', prompt: 'Escribe un artículo sobre la historia de Rockstar Games y cómo cada GTA ha sido revolucionario. Desde GTA III hasta GTA V, y por qué GTA 6 podría ser el juego más ambicioso jamás creado. Incluye datos de ventas y récords.' },
  { theme: 'tecnico', prompt: 'Escribe un artículo sobre las especificaciones técnicas esperadas de GTA 6. Analiza el motor RAGE actualizado, las plataformas confirmadas (PS5, Xbox Series X, PC), los requisitos estimados para PC, y las tecnologías como ray tracing y carga por streaming.' },
  { theme: 'easter-eggs', prompt: 'Escribe un artículo sobre los Easter Eggs y detalles ocultos descubiertos en los trailers de GTA 6. Los fans han encontrado referencias a juegos anteriores, pistas sobre la historia, y detalles del mapa. Analiza los más interesantes.' },
  { theme: 'fecha', prompt: 'Escribe un artículo actualizado sobre la fecha de lanzamiento de GTA 6. Comenta el anuncio oficial de Rockstar, las posibles ventanas de lanzamiento, los retrasos históricos de Rockstar, y qué pueden hacer los fans mientras esperan.' },
  { theme: 'musica', prompt: 'Escribe un artículo sobre la banda sonora esperada de GTA 6. Las emisoras de radio siempre han sido icónicas en GTA. Especula sobre los géneros musicales que encajarían con Vice City (reggaeton, latin trap, EDM, synthwave) y los artistas que podrían aparecer.' },
  { theme: 'economia', prompt: 'Escribe un artículo sobre el sistema económico esperado en GTA 6. Analiza cómo funcionaban las propiedades en GTA V, el sistema de inversiones, y cómo podría evolucionar la economía del juego con negocios, criptomonedas ficticias y el mercado inmobiliario de Vice City.' },
  { theme: 'vehiculos', prompt: 'Escribe un artículo sobre los vehículos confirmados y esperados en GTA 6. Analiza los coches, motos, barcos y posibles aviones vistos en los trailers. Compara con la variedad de GTA V y las mejoras en las físicas de conducción.' },
  { theme: 'policia', prompt: 'Escribe un artículo sobre el sistema de búsqueda policial en GTA 6. Rockstar ha prometido una IA policial más inteligente. Analiza las estrellas de búsqueda, las persecuciones, y cómo podría mejorar respecto a GTA V.' }
];

// Pick a random topic
const randomIndex = Math.floor(Math.random() * topics.length);
const selected = topics[randomIndex];

return [{ json: selected }];

