parameters.jsCode:
const item = $input.first();
const text = item.json.candidates[0].content.parts[0].text;

// Clean potential markdown wrapper
let cleaned = text.trim();
if (cleaned.startsWith('```json')) cleaned = cleaned.slice(7);
if (cleaned.startsWith('```')) cleaned = cleaned.slice(3);
if (cleaned.endsWith('```')) cleaned = cleaned.slice(0, -3);
cleaned = cleaned.trim();

const parsed = JSON.parse(cleaned);

const theme = $('Seleccionar Tema').first().json.theme;

// Generate slug from title
const slug = parsed.title
  .toLowerCase()
  .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-z0-9\s-]/g, '')
  .replace(/\s+/g, '-')
  .replace(/-+/g, '-')
  .substring(0, 80);

const tagColors = {
  'Análisis': '#6366f1',
  'Oficial': '#3b82f6',
  'Confirmado': '#10b981',
  'Rumor': '#f59e0b',
  'Industria': '#8b5cf6',
  'Trailer': '#ef4444'
};

const wordCount = parsed.content.split(/\s+/).length;
const readTime = Math.max(1, Math.ceil(wordCount / 200)) + ' min lectura';

const now = new Date();
const months = ['enero','febrero','marzo','abril','mayo','junio','julio','agosto','septiembre','octubre','noviembre','diciembre'];
const publishedAt = now.getDate() + ' ' + months[now.getMonth()] + ' ' + now.getFullYear();

return [{
  json: {
    slug: slug,
    tag: parsed.tag || 'Análisis',
    tag_color: tagColors[parsed.tag] || '#6366f1',
    title: parsed.title,
    subtitle: null,
    description: parsed.description,
    author: 'VI Portal',
    author_img: null,
    published_at: publishedAt,
    read_time: readTime,
    image: null,
    content: parsed.content,
    is_published: true,
    is_featured: false,
    source: 'ai'
  }
}];
